INSERT INTO question_choices (question_id, choice_number, choice_text) VALUES
(154, 1, 'They appreciate the scientifically proven superior sound quality that analog formats offer over digital streaming.'),
(154, 2, 'The physical ritual of playing a record represents a form of resistance against the pervasive digitization of daily life.'),
(154, 3, 'They are motivated primarily by the investment potential of rare and limited-edition vinyl pressings.'),
(154, 4, 'They prefer vinyl because streaming services do not carry the independent artists they most want to hear.'),
(155, 1, 'The revival has led to a sharp decline in digital streaming revenue, threatening the financial stability of the music industry.'),
(155, 2, 'Independent record stores have exploited the trend by charging excessively inflated prices for standard releases.'),
(155, 3, 'Vinyl production poses environmental concerns, and the revival may be driven more by conspicuous consumption than by genuine audio appreciation.'),
(155, 4, 'Major record labels have monopolized the vinyl market, preventing independent artists from releasing their music on the format.'),
